def create_http_request_node() -> NodeConfig:
    """Create the HTTP Request node."""

    async def handle_http_request(args: FlowArgs, flow_manager: FlowManager) -> tuple[Any, NodeConfig | None]:
        """Handler for http_request function (HTTP POST request)"""
        proceed: bool = args.get("proceed", False)
        flow_manager.state["proceed"] = proceed
        import aiohttp
        import json

        _url = "https://8d65-110-38-183-140.ngrok-free.app/saveOrder"
        _headers = {
            "Content-Type": "application/json",
        }
        _params = {}
        _data = json.dumps(flow_manager.state, default=str)
        _timeout = aiohttp.ClientTimeout(total=30)
        async with aiohttp.ClientSession(timeout=_timeout) as _session:
            async with _session.request("POST", _url, headers=_headers, params=_params, data=_data) as _response:
                _status = _response.status
                try:
                    result = await _response.json()
                except Exception:
                    result = await _response.text()
        flow_manager.state["http_request_response"] = result
        flow_manager.state["http_request_response_status"] = _status
        return result, create_end_node()

    http_request_func = FlowsFunctionSchema(
        name="http_request",
        handler=handle_http_request,
        description="Performs the configured HTTP request and returns the response.",
        properties={
            "proceed": {
                "type": "boolean",
                "description": "Set to true to proceed with this step."
            }
        },
        required=["proceed"]
    )
    return NodeConfig(
        name="http_request",
        task_messages=[
            {
                "role": "system",
                "content": "Call the available function to perform the API request, then continue based on the response."
            }
        ],
        functions=[http_request_func],
    )

